CREATE TABLE
  IF NOT EXISTS "cache_locks" (
    "key" varchar not null,
    "owner" varchar not null,
    "expiration" integer not null,
    primary key ("key")
  );

CREATE TABLE
  IF NOT EXISTS "jobs" (
    "id" integer primary key autoincrement not null,
    "queue" varchar not null,
    "payload" text not null,
    "attempts" integer not null,
    "reserved_at" integer,
    "available_at" integer not null,
    "created_at" integer not null
  );

CREATE TABLE
  IF NOT EXISTS "job_batches" (
    "id" varchar not null,
    "name" varchar not null,
    "total_jobs" integer not null,
    "pending_jobs" integer not null,
    "failed_jobs" integer not null,
    "failed_job_ids" text not null,
    "options" text,
    "cancelled_at" integer,
    "created_at" integer not null,
    "finished_at" integer,
    primary key ("id")
  );

CREATE TABLE
  IF NOT EXISTS "failed_jobs" (
    "id" integer primary key autoincrement not null,
    "uuid" varchar not null,
    "connection" text not null,
    "queue" text not null,
    "payload" text not null,
    "exception" text not null,
    "failed_at" datetime not null default CURRENT_TIMESTAMP
  );

CREATE TABLE
  IF NOT EXISTS "categories" (
    "id" integer primary key autoincrement not null,
    "uuid" varchar not null,
    "title" varchar not null,
    "slug" varchar not null,
    "description" text,
    "image" varchar,
    "is_active" tinyint (1) not null default '1',
    "created_at" datetime,
    "updated_at" datetime
  );

INSERT INTO
  categories
VALUES
  (
    1,
    'clysx3w7o0001m7w1wto7dqc9',
    'Sand, Gravel, and Decorative Aggregates',
    'sand-gravel-aggregates',
    unistr (
      '<p>The key to landscaping in California is to maximize water efficiency, and strategically use decorative rocks and fillers in places where plants can''t grow. Designing your exteriors to be functional, efficient, and aesthetically appealing is a great way to increase your enjoyment and the value of your home. To improve your landscape''s function, choose from a wide variety of filler materials, such as our sands, pea gravels, and crushed grain rock, as well as base rock materials. To increase aesthetic beauty, we offer a large variety of crushed rock, as well as decorative, polished, and premium pebbles.</p>\u000a<p style="font-size: 12px; text-align: center; margin-bottom: 15px;">Disclaimer: Product pictures of natural stone are not an exact representation of the product hues seen in natural light. There are natural color variations in stone and exact color match is not guaranteed. We recommend verifying the product color at our location before placing your order online.</p>'
    ),
    'sand-grave-decorative-rocks.jpg',
    1,
    '2024-07-19 16:31:47',
    '2025-12-06 18:29:03'
  );

