CREATE TABLE
  IF NOT EXISTS "products" (
    "id" integer primary key autoincrement not null,
    "uuid" varchar not null,
    "sku" varchar not null,
    "slug" varchar not null,
    "title" varchar not null,
    "description" text,
    "image" varchar,
    "status" tinyint (1) not null default '1',
    "created_at" datetime,
    "updated_at" datetime
  );

INSERT INTO
  products
VALUES
  (
    1,
    'clytfibo2000gg39qmybnzo0k',
    'C2BR',
    'class-2-base-rock',
    'Class 2 Base Rock',
    unistr (
      '<p>Class 2 Base Rock is a recycled product composed of fines and 3/4" crushed concrete. It is used underneath foundations, pathways, patios, and driveways. It is also used as a base underneath concrete and asphalt. Class 2 Base Rock meets the Cal Trans spec.</p>\u000d\u000a<p>We sell the Class 2 Base Rock in one cubic foot bag, we supply the bags and you fill them. For larger areas, you''ll want to purchase by the ton. We can load your truck or for a fee, have us deliver to your Bay Area location. For orders over 20 tons, please call us for direct pricing.</p>\u000d\u000a<p>Class 2 Base Rock may qualify for LEED Local/Regional Materials credit. Distances vary for each project location. Please verify the materials accordingly. </p>'
    ),
    'class2baserock.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    2,
    'clytfibof0060g39q3erbbajh',
    '34C2P',
    'class-2-permeable-base-rock',
    'Class 2 Permeable Base Rock',
    unistr (
      '<p>Class 2 Base Rock is a recycled permeable product composed of 3/4" crushed concrete and minimal fine stones allowing it to be water permeable. It is used underneath foundations, pathways, patios, and driveways or wherever permeability and stability are desired. Class 2 Permeable Base Rock meets the Cal Trans spec.</p>\u000d\u000a<p>We sell the Class 2 Permeable Base Rock in one cubic foot bag, we supply the bags and you fill them. For larger areas, you''ll want to purchase by the ton. We can load your truck, or for a fee, have us deliver the base rock to your location in the Bay Area. For orders over 20 tons, please call us for direct pricing.</p>\u000d\u000a<p>Class 2 Permeable Base Rock may qualify for LEED Local/Regional Materials credit. Distances vary for each project location. Please verify the materials accordingly. </p>'
    ),
    'class2permeableBaserock.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    3,
    'clytfibo40015g39q197rwcva',
    '14PG',
    '1-4-pea-gravel',
    '1/4" Pea Gravel ',
    unistr (
      '<p>1/4&quot; Pea Gravel is commonly used for pathways, driveways, dog runs, playgrounds, patios, and as ground cover. The smaller gravels are often used on roofs over tar.  Underground applications include drainage and pipe bedding materials for stable support.</p>\u000d\u000a<p>Please note: 1/4&quot; Pea Gravel vendor source is currently different than our previous source. Therefore, the gravel may vary in appearance. </p>\u000d\u000a<p>We sell the 1/4" Pea Gravel in one cubic foot bag, we supply the bags and you fill them. For larger areas, you''ll want to purchase by the ton. We can load your own truck,  or for a fee, have us deliver to your Bay Area location. For orders over 20 tons please call us for direct pricing.</p>\u000d\u000a<p>1/4&quot; Pea Gravel may qualify for LEED Local/Regional Materials credit. Distances vary for each project location. Please verify the materials accordingly. </p>'
    ),
    'oneQuarterInchPeaGravel.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    4,
    'clytfibo3000xg39q91qt0n72',
    'AFBF',
    'arizona-flagstone---buckskin',
    'Arizona Flagstone - Buckskin',
    unistr (
      '<ul class="product-details">\u000d\u000a<li class="item-details">Origin: North America</li>\u000d\u000a<li class="item-details">Classification Sandstone</li>\u000d\u000a<li class="item-details">Color Range: Warm Tones</li>\u000d\u000a<li class="item-details">Finish: Natural Cleft</li>\u000d\u000a<li class="item-details">Applications: Walkways, Pathways, Patios, Accents</li>\u000d\u000a</ul> \u000d\u000a\u000d\u000a\u000d\u000a<p>Arizona Flagstone is a standup select grade flagstone that is available in large sheets of random shapes. It can be used for patios, stepping stones or any flat surface that you want to cover with flagstone. Due to the natural cleft and the porosity, this natural paving stone spalls, meaning, the top layer of the stone peels off with wear. In a shady damp area, particularly in winter months, algae and moss growth which can permanently stain the stone. Some landscapes desire this look but to deter algae and moss growth, use a stone sealer.</p><p>This sedimentary sandstone is available in a variety of southwest colors: Sedona Red, Rosa, Peach, Buckskin, Buff, Classic Oak, and variations in between.</p>\u000d\u000a<p>Available in two thickness: 1&quote;-1  3/4 &quote; and thinner 1&quote; minus.</p>\u000d\u000a<p>For sand setting application, use the thicker 1&quote; - 1  3/4 &quote; flagstone.\u000d\u000aFor the 1&quote; minus flagstone, special care needs to be taken since the stone is very fragile and brittle. It is intended to be set in mortar on a concrete base to protect it from cracking</p>'
    ),
    'arizona-flagstone-buckskin.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    5,
    'clytfibof005zg39qeg41osdg',
    '14-FB',
    '1-4-fir-bark',
    '1/4" - Fir Bark',
    '<p class="editor-paragraph" dir="ltr"><span style="white-space: pre-wrap;">1/4 " Fir Bark is the smallest remaining particles from sifting the fir barks. Mix in with clay soil to loosen and aerate as an organic amendment. Provides moisture retention and aeration. Due to the small size of the bark, breaks down faster than Fine Redwood Amendment.</span></p><p class="editor-paragraph" dir="ltr"><span style="white-space: pre-wrap;">We sell the bark in one cubic foot bags, we supply the bags and you fill them. For large areas, you''ll want to purchase by the cubic yard. We can load your truck or for a fee, have us deliver to your home or job site.</span></p>',
    '14-fur-bark.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    6,
    'clytfibof0061g39qomlxjp5j',
    '1OS',
    '1-olympia-sand',
    '#1 Olympia Sand',
    '<p>Olympia Sands is used primarily for making mortar or stucco. However, Olympia Sand #1 is screened and washed. It is highly desirable for children''s sandboxes, playgrounds, and the sand used for volleyball courts.</p><p>Lyngso Garden Materials sell #1 Olympia Sand in one cubic foot bags.  We supply the bags and you fill them! For larger areas, you''ll want to purchase by the ton. We can load your truck or for a fee, have us deliver to your jobsite. For orders over 20 tons please call us for direct pricing.</p><p>#1 Olympia Sand may qualify for LEED Local/Regional Materials credit. Distances vary for each project location. Please verify the materials accordingly.</p>',
    '1-olympia-sand.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    7,
    'clytfibo2000hg39qf7fbfufc',
    '2OS',
    '2-olympia-sand',
    '#2 Olympia Sand',
    '<p>Olympia Sand #2 is used for making plaster, mortar or stucco and can also be used for sandboxes.  It is a more coarse material than Olympia Sand #1, which provides it with better construction properties.</p><p>We sell both Olympia Sand #1 and Olympia Sand #2 in one cubic foot bags.  Lyngso will supply the bags and you can fill as many as you need. For larger areas, you''ll want to purchase Olympia Sand by the ton. We can load your truck for you, or for a fee, you can use our rental truck and load the sand on your own, or have us deliver to you. For orders over 20 tons please call us for direct pricing.</p><p>#2 Olympia Sand may qualify for LEED Local/Regional Materials credit. Distances vary for each project location. Please verify the materials accordingly.</p>',
    '2-olympia-sand.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
