INSERT INTO
  products
VALUES
  (
    14,
    'clytfibnz0007g39qt7laiyg0',
    'LIGNA PEAT',
    'ligna-peat',
    'Ligna Peat',
    '<p class="editor-paragraph" dir="ltr"><span style="white-space: pre-wrap;">Ligna Peat is 100% pure, organic, and sustainably harvest redwood fiber. A sustainable alternative to Peat Moss. Ligna Peat provides beneficial organic matter for a sustained period of time without rapid decomposition. Commonly used for aeration and water retention within the soil.</span></p><p class="editor-paragraph" dir="ltr"><span style="white-space: pre-wrap;">We sell Ligna Peat in one cubic foot bags, we supply the bags and you fill them. For large areas you''ll want to purchase by the cubic yard. We can load your truck or for a fee, have us deliver to your home or job site.</span></p><p class="editor-paragraph" dir="ltr"><span style="white-space: pre-wrap;">Ligna Peat is CDFA OIM listed for organic use and is a FSC certified product.</span></p>',
    'lingaPeat.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:03'
  );

INSERT INTO
  products
VALUES
  (
    15,
    'clytfibo2000dg39qmo75wll4',
    'ORGANIC-AMENDMENT',
    'organic-amendment-mix',
    'Organic amendment Mix',
    '<p>Organic Amendment Mix is a blend of Organic Green Waste Garden Compost, Redwood Sawdust, and Organic Feather Meal. This mix is generally used for improving most soils in water retention and aeration. Amendment Mix helps to open up clay for rainwater to be held and to be moved through the soil. Excellent for new sod installations and for generic all-purpose soil amending. </p><p>For additional organic fertilizer and microbiology, mix in Bio-Live 5-4-2 while amending. </p><p>Lyngso''s Organic Amendment Mix is an organic substitute for Nitrolized Redwood Amendment. </p><p>CDFA OIM LISTED FOR ORGANIC USE</p><p>We sell the Organic Amendment Mix in one cubic foot bag, we supply the bags and you fill them. For large areas, you''ll want to purchase by the cubic yard. We can load your truck or for a fee, have us deliver to your home or job site. For orders over 20 cubic yards, please call us for direct pricing.</p>',
    'organicAmendmentMix.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    16,
    'clytfibmz0001g39qynd4058g',
    'RS',
    'redwood-sawdust',
    'Redwood Sawdust',
    '<p>Redwood Sawdust is an all-natural redwood byproduct of the lumber mills. Not treated with any chemicals.  It is typically used as a soil amendment to help break up clay and aerate compacted soil.</p><p>For additional organic fertilizer and microbiology, mix in Bio-Live 5-4-2 while amending. </p><p>We sell the Redwood Sawdust in one cubic foot bags, we supply the bags and you fill them. For large areas, you''ll want to purchase by the cubic yard. We can load your truck or for a fee, have us deliver to your home or job site</p>',
    'redwoodSawdust.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    17,
    'clytfibo3000rg39q4f43a4ci',
    'COMPOST-MULCH',
    'composted-mulch-limited-quantity',
    'Composted Mulch - Limited Quantity',
    '<p>Composted Mulch is derived from composted wood from composting green waste facility. This material has been through a 9–20-week composting process. During the composting period, accepted thermophilic composting procedures are performed to accomplish pathogen reduction through time and temperature (130-170 degrees (F) throughout the composting period). This ensures a thoroughly composted, weed and pathogen free product. </p><p>Composted Mulch is screened to 1”-3’’ in size and contains fines. Although Composted Mulch is listed as OMRI organic, it is still a recycled product so it may occasionally contain small inert debris such as plastic or glass.</p><p>Compost Mulch is an excellent ground cover that greatly enhances the aesthetic appearance of landscapes. Composted Mulch can help retain moisture, control weeds, and help prevent erosion. In addition, this Composted Mulch has demonstrated to be less combustible and less floatable compared to other wood mulches. </p><p>Composted Mulch is also considered as a no-float mulch and is highly recommended for use in Bioretention areas. Composted Mulch is OMRI listed organic as a soil amendment and a weed and disease control product. </p> <p>Composted Mulch complies with SB 1383 requirements and is produced in a fully permitted composting facility conforming to the State of California regulations set forth by the California Integrated Waste Management Board (CIWMB) Title 14, Division 7 California Code of Regulations governing composting operations. </p> <p>Limited quantity available. </p>',
    'compostMulch.png',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    18,
    'clytfibog006pg39q7ve162on',
    'GRB',
    'ground-redwood-bark-',
    'Ground Redwood Bark ',
    '<p>Ground Redwood Bark is the bark from redwood trees that have been double ground. It is a stringy, fluffy, and fibrous bark that ranges in size around 1-2 inches and less. Often referred to as "Gorilla Hair" or "Monkey Fur". However, our Ground Redwood Bark is double ground and has finer texture. It does hold onto water and is lightweight. Not recommended for windy areas or steep slopes. Depending on the grade, holds well in moderately sloped areas. Great for indoor or outdoor potted plants. </p><p>We sell the bark in one cubic foot bags, we supply the bags and you fill them. For large areas, you''ll want to purchase the bark by the cubic yard. We can load your truck or for a fee you can use our rental dump truck or have us deliver the bark to you. For large orders over 60 yards please call for a direct price.</p><p><a href="https://www.youtube.com/watch?v=W_xlAV7gKjI" target="blank">Information Link</a></p>',
    'groundRedwoodBark.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    19,
    'clytfiboi007jg39qo0yw0y0m',
    'MA CHIP',
    'mahogany-chip',
    'Mahogany Chip',
    '<p>Mahogany Chip is an attractive processed wood product that''s dyed with a natural UV protectant color, ferric oxide. Clean byproduct from sawmills, no post consumer wood is used. Therefore, no paints or toxins in the mulch. Great for commercial applications or wherever longevity of the vibrant color is desired. Mahogany Chip varies in size quite drastically, from 2" to 6" but typically stays towards the smaller size. Our batches vary from day to day, so it''s best to check with us directly if you need to match a specific size. If you are trying to match your exiting Mahogany Chip, consider taking a trip to our yard to verify the size before your purchase.  Although Mahogany Chip will retain its color longer than most non-colored chips, in rainy season however, the color could wash away when it is exposed to water or sits in water for an extended period of time. It is advisable to install the chips once the rains have passed.</p><p>We sell the mulch in one cubic foot bags, we supply the bags and you fill them. For larger areas, you''ll want to purchase the mulch by the cubic yard. We can load your truck or for a fee, have us deliver the mulch to your home or jobsite. For orders over 50 cubic yards, please call us for direct pricing.</p><p><a href="https://www.youtube.com/watch?v=D8gjB759-hQ" target="blank">Information Link</a></p>',
    'mahoganyChip.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    20,
    'clytfiboh007bg39q77ulaf3h',
    'MMFB',
    'mini-mulch-fir-bark',
    'Mini Mulch Fir Bark',
    '<p>Mini Mulch Fir Bark is 1/4-3/8 inch in size. The sun fades the natural red bark to a weathered grey over time. Often mistaken for redwood, it is indeed the bark of fir trees. Very attractive and popular mulch for vegetable garden beds. The Mini Mulch will decompose faster than larger mulch and will eventually turn into organic soil amendment.</p><p>We sell the bark in one cubic foot bags, we supply the bags and you fill them. For larger areas, you''ll want to purchase the bark by the cubic yard. We can load your truck or for a fee, have us deliver the bark to you. For orders over 45 yards please call us for direct pricing.</p><p><a href="https://www.youtube.com/watch?v=aBKZYxsMf90" target="blank">Information Link</a></p>',
    'miniMulchFirBark.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    21,
    'clytfiboi007hg39qrwk9svu9',
    'MOCHA CHIP',
    'mocha-chip',
    'Mocha Chip',
    '<p>Mocha Chip is an attractive processed redwood that''s dyed with a natural UV protectant color, ferric oxide. It''s a clean byproduct from sawmills, no post-consumer wood is used. Therefore, no paints or toxins in the mulch. Great for commercial applications or wherever longevity of the vibrant color is desired. Mocha Chip varies in size quite drastically, from 2" to 6" but typically stays towards the smaller size. </p><p>Our shipment varies from day to day, so it''s best to check with us directly if you need to match a specific size. If you are trying to match your exiting Mocha Chip, consider taking a trip to our yard to verify the size before your purchase.  Although Mocha Chip will retain its color longer than most non-colored chips, in the rainy season, however, the color could wash away when it is exposed to water or sits in water for an extended period of time. It is advisable to install the chips once the rains have passed.</p><p>Freshly produced Mocha Chips may be subject to colorant wash off and can stain driveways. Therefore, it is recommended that the mulch is dumped on a tarp. The colorant can also stain clothing or be tracked onto carpet or furniture by pets. </p><p>We sell the mulch in one cubic foot bags, we supply the bags and you fill them. For larger areas, you''ll want to purchase the mulch by the cubic yard. We can load your truck or for a fee, have us deliver to your home or jobsite. For orders over 50 cubic yards, please call us for direct pricing.</p><p><a href="https://www.youtube.com/watch?v=I1ZOsWuYzzs" target="blank">Information Link</a></p>',
    'mochaChip.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    22,
    'clytfiboh007ag39qo5tqbxwm',
    'PF',
    'playground-fiber',
    'Playground Fiber',
    '<p>Playground Fiber is engineered natural wood that is 1/2" - 1" in size. Made out of California white conifers, the fiber is processed to have elongated blunt or soft chopped ends, therefore, more resistant to splintering. Chips do not contains any toxins or chemical additives. No recycled by-products, processed woods or fillers are used. Meets ADA, ASTM and CPSC playground surfacing standards for impact absorption, accessibility and safety. Approved for use in public playgrounds, parks or pathways. </p><p>We sell the Playground Fiber in one cubic foot bags, we supply the bags you fill them. For larger areas, you''ll want to purchase the Playground Fiber by the cubic yard. We can load your truck or for a fee, have us deliver to your home or jobsite. For orders over 45 cubic yards, please call us for direct pricing.</p><p><a href="https://www.youtube.com/watch?v=EJ1EtKcxSno" target="blank">Information Link</a></p>',
    'playgroundFiber.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    23,
    'clytfiboh007cg39qw1xsx2tl',
    'PAM',
    'premium-arbor-mulch',
    'Premium Arbor Mulch',
    '<p>Premium Arbor Mulch is 100% clean tree trimming from local urban forests. The tree trimmers and arborists dropping off the trimmings and wood are monitored closely for quality. Mulch contains a conglomerate of bark, wood chips, and some leaves. Provides protection and food for the life in your soil. Mulch will eventually decompose and will turn into organic soil amendment over time. Depending on the grade, holds well in moderately sloped areas. Excellent for Sheet Mulching applications! Click on the Information Link below to learn more about Sheet Mulching!</p><p>We sell the mulch in one cubic foot bags, we supply the bags and you fill them. For larger areas, you''ll want to purchase the mulch by the cubic yard. We can load your truck or for a fee, have us deliver the mulch to your home or jobsite. For orders over 50 cubic yards, please call us for direct pricing.</p><p><a href="https://www.lyngsogarden.com/community-resources/sheet-mulching/" target="blank">Information Link</a></p>',
    'premiumArborMulch.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
