INSERT INTO
  products
VALUES
  (
    49,
    'clytfibo6001tg39ql6v85phd',
    'BFS',
    'blue-fines-stabilized',
    'Blue Fines Stabilized',
    unistr (
      '<p>Blue Fines Stabilized stone is not a substitute for a non-permeable concrete or asphalt surface. This product was developed to mitigate erosion during heavy rains and is perfect for pathways and between flagstone and pavers. The surface will always have some loose grit that can be tracked. \u000d\u000a</p>\u000d\u000a<p>It is critical to follow the proper installation instructions to ensure the performance of the product. Lyngso will not be responsible for unsatisfactory results due to improper installation. See the attached installation guidelines. </p>\u000d\u000a<p>Blue Fines may qualify for LEED Local/Regional Materials credit. Distances vary for each project location. Please verify the materials accordingly.</p>\u000d\u000a<p>Blue Fines are a 1/4" minus rock that is perfect for pathways and between flagstone and pavers.  Stabilized Blue Fines are available in stock and are pre-mixed with a stabilizer. For areas where the stability of the pathway fines is desired, a stabilizer can be added. We only use a non-toxic, natural stabilizer. </p><p>Blue Fines should be spread and compacted at 2"- 4". There may be a 15-20% shrinkage during compaction so plan ahead with your calculations. Stabilized Blue Fines will need to be set with spraying water once compacted. Curing time is necessary before using the space and varies depending on the weather.\u000d\u000a</p><p>We sell the Blue Fines in one cubic foot bag; we supply the bags and you fill them. For larger areas, you''ll want to purchase by the ton. We can load your truck or for a fee, have us deliver to your home or jobsite. For orders over 20 tons, please call us for direct pricing.</p><p>Blue Fines may qualify for LEED Local/Regional Materials credit. Distances vary for each project location. Please verify the materials accordingly.</p>'
    ),
    'blueFinesStabilized.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
