VALUES
  (
    78,
    'clytfibob0041g39qiwsekz4b',
    'AGB',
    'amador-granite-boulder',
    'Amador Granite Boulder',
    unistr (
      '<ul><li>Origin: North America</li><li>Classification: Granite</li><li>Color Range: Greys, Whites, Tans</li><li>Finish: Natural</li><li>Application: Accents</li></ul>\u000d\u000a<p>Coarse grain granite boulders with an interesting angular and sculptural elements. Many boulders might contain plug & feather marks. Reclaimed quarry tailings. Remnants of mid-1800s mining operations. Natural local stone.\u000d\u000a</p>\u000d\u000a<p>Amador Granite Boulders may qualify for LEED Local/Regional Materials credit. Distances vary for each project location. Please verify the materials accordingly.</p>\u000d\u000a'
    ),
