    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    86,
    'clytfiboc004lg39q8i4auy4q',
    'BBBLP',
    'black-button-la-paz-pebbles',
    'Black Button La Paz Pebbles',
    unistr (
      '<p>Black Button La Paz Pebbles are smaller than their standard brother, La Paz Pebbles.  La Paz Pebbles are often called Mexican Beach Pebbles, hand collected on the beaches of Mexico. These natural beach pebbles are one of kind, sculpted by oceanic currents. Smooth with natural matte hues, blacks, grays, and charcoals in this set, La Paz pebbles will make a statement in your landscape design.</p><p>La Paz pebbles are oval in shape. Sizes may vary slightly from shipment to shipment. Hand sorted, not screened.</p><p>Please note:</p><p>Actual Button size La Paz range from 3/4" to 1 1/4".\u000d\u000a</p><p>As an alternative to Black Button La Paz Pebbles, consider our Hama Pebbles.</p>\u000d\u000a'
    ),
    'blackButtonLaPazPebbles.jpeg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
