    'oyster-shell-bocce-blend',
    'Oyster Shell Bocce Blend',
    unistr (
      '<p>Oyster Shell Bocce Blend is specially formulated for use in bocce ball courts. A mixture of crushed oyster shells and fines for a natural, traditional surface. This bocce blend provides the players with a smooth rolling surface and has proper drainage when it rains.</p><p>As an alternative to Bocce Blend, you may want to consider using our Path Fines to construct your Bocce Ball Court.</p>\u000d\u000a'
    ),
    'oysterShellBocceBlend.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

