INSERT INTO
  products
VALUES
  (
    120,
    'clytfibog006qg39qby5b3dzg',
    unistr ('CGS5035\u0009\u0009'),
    'coregravel-driveway-',
    'Coregravel Driveway ',
    unistr (
      '<ul><li>CORE Gravel™ 50-35HD</li><li>Use: Heavy Duty - commercial paths, residential driveways, </li><li>restaurant patios, and more</li><li>Gravel size: 7 – 15 mm</li><li>Cell Size: 50 mm wide x 35 mm deep</li><li>Cell Wall Thickness: 2.0 mm</li><li>Sheet Size: 1.15 m x .78 m (= 9.7 sq.ft.)</li><li>Cell Colour: White (virgin plastic) </li><li>Geotextile Fabric: Yes</li><li>Compressive Strength: 150 t/m2 (empty)</li><li>Suitable for vehicles: Yes</li></ul>\u000d\u000a\u000d\u000a<p>CORE Gravel™ is a gravel stabilizing system that consists of a foundation of connected honeycomb-celled panels with a geotextile backing. Once filled with gravel this system is ideal for public spaces, vehicle or pedestrian traffic with no compromise in strength and durability. This eco-friendly system costs less than other parking systems, including asphalt, concrete and block pavers.</p>\u000d\u000a<p>CORE Gravel™ solves the problems associated with loose gravel; sinking, migrating and forming ruts. This is a proven solution for hassle-free gravel paving for all types of vehicle or pedestrian traffic with no compromise in strength and durability. The underside incorporates a durable geotextile which is heat welded to each cell, allowing water to drain easily while preventing weed growth. All panel edges have an interlocking system that makes for easy installation, even on steep grades.</p>\u000d\u000a<p>Proprietary manufacturing process provides a rigid honeycomb core design that holds its uniform hexagon shape while providing maximum load bearing. When filled with gravel the product is practically invisible, making for attractive driveways, pathways and patio installations. This porous and eco-friendly surface allows for storm water to permeate into the soil, dramatically reducing runoff problems.</p>\u000d\u000a<p>CORE Gravel™ is an excellent gravel stabilizing system.</p>\u000d\u000a\u000d\u000a<span id="pdf-link"><a href="http://localhost:5001/pdf/50-35_gravel_spec_sheet-1.pdf" target="_blank"><span class="pdf-ico"></span><span class="pdf-view">View Product Information</span></a></span>\u000d\u000a\u000d\u000a\u000d\u000a'
    ),
    'CoregravelDriveway.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    121,
    'clytfibog006ng39q9a2l9hxg',
    unistr ('CGS3818\u0009\u0009\u0009'),
    'coregravel-pathway-',
    'Coregravel Pathway ',
    unistr (
      '<ul><li>CORE Path™ 38-18</li><li>Use: Heavy Duty - commercial paths, residential driveways, </li><li>restaurant patios, and more</li><li>Gravel size: 3 - 10 mm</li><li>Cell Size: 38 mm wide x 18 mm deep/li><li>Cell Wall Thickness: 1.0 mm</li><li>Sheet Size: 1.15 m x .8 m (= 9.9 sq. ft.)</li><li>Cell Colour: White (virgin plastic) </li><li>Geotextile Fabric: Yes</li><li>Compressive Strength: 40 t/m2 (empty)</li><li>Suitable for vehicles: No, pedestrian traffic only</li></ul>\u000d\u000a\u000d\u000a<p>CORE Gravel™ is a gravel stabilizing system that consists of a foundation of connected honeycomb-celled panels with a geotextile backing. Once filled with gravel this system is ideal for public spaces, vehicle or pedestrian traffic with no compromise in strength and durability. This eco-friendly system costs less than other parking systems, including asphalt, concrete and block pavers.</p>\u000d\u000a<p>CORE Gravel™ solves the problems associated with loose gravel; sinking, migrating and forming ruts. This is a proven solution for hassle-free gravel paving for all types of vehicle or pedestrian traffic with no compromise in strength and durability. The underside incorporates a durable geotextile which is heat welded to each cell, allowing water to drain easily while preventing weed growth. All panel edges have an interlocking system that makes for easy installation, even on steep grades.</p>\u000d\u000a<p>Proprietary manufacturing process provides a rigid honeycomb core design that holds its uniform hexagon shape while providing maximum load bearing. When filled with gravel the product is practically invisible, making for attractive driveways, pathways and patio installations. This porous and eco-friendly surface allows for storm water to permeate into the soil, dramatically reducing runoff problems.</p>\u000d\u000a<p>CORE Gravel™ is an excellent gravel stabilizing system.</p>\u000d\u000a\u000d\u000a<span id="pdf-link"><a href="http://localhost:5001/pdf/38-18_core_path_spec_sheet-1.pdf" target="_blank"><span class="pdf-ico"></span><span class="pdf-view">View Product Information</span></a></span>\u000d\u000a\u000d\u000a\u000d\u000a'
    ),
    'CoregravelPathway.jpg',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

INSERT INTO
  products
VALUES
  (
    122,
    'clytfiboh007fg39qwq8n0fc4',
    'GATORNW',
    'gator-geotextile-fabric',
    'Gator Geotextile Fabric',
    unistr (
      '<p>GATOR FABRIC GF4.4 (100 lbf) is a needle punched non-woven geotextile made of polypropylene fibers. GATOR FABRIC GF4.4 geotextile is ideal for drainage, filtration and will allow water flow of 135 gallons per minutes per square foot (613 L/min/sq. m.) in paver or retaining wall applications. Its filament fibers are used for soil separation and drainage. They combine high durability along with excellent physical and hydraulic properties. It is non-biodegradable and resistant to most soil chemicals. Great for patios, walkways and driveways.\u000d\u000a</p>\u000d\u000a\u000d\u000a<p>IDEAL FOR: </p>\u000d\u000a\u000d\u000a<ul>\u000d\u000a<li>Drainage control</li>\u000d\u000a<li>Protection against erosion </li>\u000d\u000a<li>Behind retaining walls</li>\u000d\u000a<li>Paver sub base foundation</li>\u000d\u000a<li>Gator Base foundation application</li>\u000d\u000a<li>General landscape</li>\u000d\u000a<li>Soil separation</li>\u000d\u000a</ul>\u000d\u000a<p>FEATURES</p>\u000d\u000a<ul>\u000d\u000a<li>Specially treated to be hydrophilic, it allows high-water flow</li>\u000d\u000a<li>(135 Gal/min/sq. ft. (613 L/min/sq. m.))</li>\u000d\u000a<li>Drainage and filtration</li>\u000d\u000a<li>Soil separation</li>\u000d\u000a<li>Erosion control</li>\u000d\u000a<li>UV-Resistance</li>\u000d\u000a<li>Inert to soil chemicals (Alkalis, Acids)</li>\u000d\u000a<li>Inert to biological degradation</li>\u000d\u000a<li>Easy to handle</li>\u000d\u000a<li>High strength/dimensionally stable</li>\u000d\u000a</ul>\u000d\u000a\u000d\u000a<p>PLEASE NOTE: </p>\u000d\u000a<p>Gator Geotextile Fabric is sold in 6’ width and in 1’ lineal foot increments. It is cut to order and only comes in 6'' width.  </p>\u000d\u000a<p>Full rolls of 300'' length can be purchased by special order. </p>\u000d\u000a\u000d\u000a<p><a href="https://alliancegator.com/gator-grids-fabrics/gator-fabric-gf4-4/" target="_blank">Information Link<a></p>\u000d\u000a\u000d\u000a\u000d\u000a'
    ),
    'GatorGeotextileFabric.png',
    1,
    '2024-07-20 01:06:54',
    '2025-12-06 18:29:04'
  );

