INSERT INTO
  products
VALUES
  (
    341,
    'cm8ryp6y20003eph0cpbfe65g',
    'ASNLS',
    'arizona-snap-ledger-stone',
    'Arizona Snap Ledge Stone',
    '<p class="editor-paragraph" dir="ltr"><span style="white-space: pre-wrap;">Origin: North America Classification: Sandstone Color Range: Warm Tones Finish: Natural Split Applications: Veneers, Landscape Borders Arizona Snapped Ledge Stone is a great choice for any vertical surface that you want to cover. Due to the natural porosity, this ledge stone spalls, meaning, the top layer of the stone peels off with wear. In a shady damp area, particularly in winter months, algae and moss growth which can permanently stain the stone. Some landscapes desire this look but to deter algae and moss growth, use a stone sealer. The depth of the ledge stone ranges from 4" - 6". Arizona Snapped Ledge Stone is available in stock only in Buff color. However, the following colors are available for special order: Sedona Red, Rosa, Peach, Buckskin, Classic Oak, and variations in between.</span></p>',
    'arizona-sanpped-ledger-stone.jpeg',
    1,
    '2025-03-27 23:05:38',
    '2025-12-06 18:29:04'
  );

