  (
    63,
    'Luna Grey Sandstone',
    unistr (
      '<ul>\u000d\u000a<li>Origin: Asia</li>\u000d\u000a<li>Classification: Sandstone</li>\u000d\u000a<li>Color Range: Grays</li>\u000d\u000a<li>Finishes: Natural Cleft</li>\u000d\u000a<li>Application: Walkways, Pathways, Pavers, Veneers, Patios, Accents</li>\u000d\u000a</ul>\u000d\u000a\u000d\u000a<p>Luna Grey Flagstone are a light grey colored sandstone. 2” thickness.<p>'
