  (
    101,
    'Desert Brown Fines',
    unistr (
      '<p>Desert Brown Fines are brown decomposed 3/8" minus quarry fines. Commonly used for decorative pathways, parking areas, utility yards and dog runs. Desert Brown Fines packs well due to the larger quarry gravel and will have visible grits on the surface layer. Permeable material. Desert Brown Fines should be spread 3"-4" deep and compacted. \u000d\u000a</p>\u000d\u000a<p>We sell the Desert Brown Fines in one cubic foot bag; we supply the bags and you fill them. For larger areas, you''ll want to purchase by the ton. We can load your truck or for a fee, have us deliver to your home or jobsite. For orders over 20 tons, please call us for direct pricing.</p>\u000d\u000a'
    ),
    'products',
    50
  );

INSERT INTO
  search_index_content
VALUES
  (
    102,
    'Sunset Gold Path Fines',
    unistr (
      '<p>Sunset Gold Path Fines are 1/4" minus gold granite fines and is typically referred to as decomposed granite. Sunset Gold Path Fines are gold and tan in color and are used for pathways, driveways, parking areas, and between flagstone and pavers. Sunset Gold Path Fines is permeable and once compacted, top layer will still have some loose fines.  Apply 2" deep, water and roll, then add a 1" - 2" layer to complete the project. \u000d\u000a</p>\u000d\u000a<p>We sell the Sunset Gold Path Fines in one cubic foot bag, we supply the bags and you fill them. For larger areas, you''ll want to purchase by the ton. We can load your truck or for a fee, have us deliver to you. For orders over 20 tons please call us for direct pricing.</p><p>Sunset Gold Path Fines may qualify for LEED Local/Regional Materials credit. Distances vary for each project location. Please verify the materials accordingly.</p>\u000d\u000a'
    ),
    'products',
    51
  );

INSERT INTO
