INSERT INTO
  search_index_content
VALUES
  (
    184,
    'Antigo Boulder ',
    unistr (
      '<ul>\u000d\u000a<li>Origin: North America</li>\u000d\u000a<li>Classification: Limestone</li>\u000d\u000a<li>Color Range: White, Cream, Light Gray, Buff</li>\u000d\u000a<li>Finish: Natural</li>\u000d\u000a<li>Application: Accents, Focal Features</li>\u000d\u000a</ul>\u000d\u000a\u000d\u000a<p>Antigo Boulders are a natural cream and buff colored limestone boulders. Attractive as a focal feature in a garden. </p>\u000d\u000a<p>Boulder densities vary depending on the geological makeup. Therefore, it is hard to accurately predict the weight of the boulders without weighing them. However, as a general approximation, please use the following size and weight guide:</p>\u000d\u000a\u000d\u000a<ul>\u000d\u000a<li>1'' x 1'' x 1'' = 165 lbs. (0.08 tons)</li>\u000d\u000a<li>1'' x 1'' x 1.5'' = 248 lbs. (0.12 tons)</li>\u000d\u000a<li>1'' x 2'' x 1.5'' = 495 lbs. (0.25 tons)</li>\u000d\u000a<li>1.5'' x 2'' x 1.5'' = 743 lbs. (0.37 tons)</li>\u000d\u000a<li>1.5'' x 2'' x 2'' = 990 lbs. (0.51 tons)</li>\u000d\u000a<li>2'' x 2'' x 2'' = 1320 lbs. (0.66 tons)</li>\u000d\u000a<li>2'' x 2'' x 2.5'' = 1650 lbs. (0.85 tons)</li>\u000d\u000a<li>2'' x 2'' x 3'' = 1980 lbs. (0.99 tons)</li>\u000d\u000a<li>2'' x 3'' x 2.5'' = 2475 lbs. (1.24 tons)</li>\u000d\u000a<li>2'' x 3'' x 3'' = 2970 lbs. (1.49 tons)</li>\u000d\u000a<li>2.5'' x 3'' x 2.5'' = 3094 lbs. (1.55 tons)</li>\u000d\u000a<li>2.5'' x 3'' x 3'' = 3713 lbs. (1.86 tons)</li>\u000d\u000a<li>3'' x 3'' x 3'' = 4455 lbs. (2.23 tons)</li>\u000d\u000a</ul>\u000d\u000a\u000d\u000a\u000d\u000a'
    ),
    'products',
    134
  );

INSERT INTO
  search_index_content
VALUES
  (
    185,
    'Bouquet Canyon Boulders',
    unistr (
      '<ul>\u000d\u000a<li>Origin: North America</li>\u000d\u000a<li>Classification: Schist</li>\u000d\u000a<li>Color Range: Greens, Greys, Tans, Rusts</li>\u000d\u000a<li>Finish: Natural</li>\u000d\u000a<li>Application: Accents</li>\u000d\u000a</ul>\u000d\u000a\u000d\u000a<p>Bouquet Canyon Boulders are green-gray schist boulders with natural rust bronze coloration. Natural local stone.</p>\u000d\u000a<p>Bouquet Canyon Boulders may qualify for LEED Local/Regional Materials credit. Distances vary for each project location. Please verify the materials accordingly.</p>\u000d\u000a\u000d\u000a<p>Boulder densities vary depending on the geological makeup. Therefore, it is hard to accurately predict the weight of the boulders without weighing them. However, as a general approximation, please use the following size and weight guide:\u000d\u000a</p>\u000d\u000a\u000d\u000a<ul>\u000d\u000a<li>1'' x 1'' x 1'' = 165 lbs. (0.08 tons)</li>\u000d\u000a<li>1'' x 1'' x 1.5'' = 248 lbs. (0.12 tons)</li>\u000d\u000a<li>1'' x 2'' x 1.5'' = 495 lbs. (0.25 tons)</li>\u000d\u000a<li>1.5'' x 2'' x 1.5'' = 743 lbs. (0.37 tons)</li>\u000d\u000a<li>1.5'' x 2'' x 2'' = 990 lbs. (0.51 tons)</li>\u000d\u000a<li>2'' x 2'' x 2'' = 1320 lbs. (0.66 tons)</li>\u000d\u000a<li>2'' x 2'' x 2.5'' = 1650 lbs. (0.85 tons)</li>\u000d\u000a<li>2'' x 2'' x 3'' = 1980 lbs. (0.99 tons)</li>\u000d\u000a<li>2'' x 3'' x 2.5'' = 2475 lbs. (1.24 tons)</li>\u000d\u000a<li>2'' x 3'' x 3'' = 2970 lbs. (1.49 tons)</li>\u000d\u000a<li>2.5'' x 3'' x 2.5'' = 3094 lbs. (1.55 tons)</li>\u000d\u000a<li>2.5'' x 3'' x 3'' = 3713 lbs. (1.86 tons)</li>\u000d\u000a<li>3'' x 3'' x 3'' = 4455 lbs. (2.23 tons)</li>\u000d\u000a</ul>\u000d\u000a\u000d\u000a\u000d\u000a'
    ),
    'products',
    135
  );

INSERT INTO
  search_index_content
VALUES
  (
    186,
    'Chiefcliff Boulders',
    unistr (
      '<ul>\u000d\u000a<li>Origin: North America</li>\u000d\u000a<li>Classification: Argillite </li>\u000d\u000a<li>Color Range: Grays, Blues, Tans</li>\u000d\u000a<li>Finish: Natural</li>\u000d\u000a<li>Application: Accents</li>\u000d\u000a</ul>\u000d\u000a\u000d\u000a<p>Chiefcliff Boulders are decorative gray angular Argillite landscape boulders. These are sedimentary rocks with green moss and lichen highlights. Blocky and irregular shapes. Weight is from 150 pounds to over 4,000 pounds. Size range varies from 16 inches wide by 18 inches tall by 18 inches long to 30 inches wide by 48 inches tall by 60 inches long. Colors range from light grays, blue grays to browns.</p>\u000d\u000a<p>Boulder densities vary depending on the geological makeup. Therefore, it is hard to accurately predict the weight of the boulders without weighing them. However, as a general approximation, please use the following size and weight guide:\u000d\u000a</p>\u000d\u000a\u000d\u000a<ul>\u000d\u000a<li>1'' x 1'' x 1'' = 165 lbs. (0.08 tons)</li>\u000d\u000a<li>1'' x 1'' x 1.5'' = 248 lbs. (0.12 tons)</li>\u000d\u000a<li>1'' x 2'' x 1.5'' = 495 lbs. (0.25 tons)</li>\u000d\u000a<li>1.5'' x 2'' x 1.5'' = 743 lbs. (0.37 tons)</li>\u000d\u000a<li>1.5'' x 2'' x 2'' = 990 lbs. (0.51 tons)</li>\u000d\u000a<li>2'' x 2'' x 2'' = 1320 lbs. (0.66 tons)</li>\u000d\u000a<li>2'' x 2'' x 2.5'' = 1650 lbs. (0.85 tons)</li>\u000d\u000a<li>2'' x 2'' x 3'' = 1980 lbs. (0.99 tons)</li>\u000d\u000a<li>2'' x 3'' x 2.5'' = 2475 lbs. (1.24 tons)</li>\u000d\u000a<li>2'' x 3'' x 3'' = 2970 lbs. (1.49 tons)</li>\u000d\u000a<li>2.5'' x 3'' x 2.5'' = 3094 lbs. (1.55 tons)</li>\u000d\u000a<li>2.5'' x 3'' x 3'' = 3713 lbs. (1.86 tons)</li>\u000d\u000a<li>3'' x 3'' x 3'' = 4455 lbs. (2.23 tons)</li>\u000d\u000a</ul>\u000d\u000a\u000d\u000a\u000d\u000a'
    ),
    'products',
    136
  );

INSERT INTO
