INSERT INTO
  search_index_content
VALUES
  (
    188,
    'Recycled Sand',
    '<p class="editor-paragraph" dir="ltr" style="text-align: left;"><b><strong class="editor-text-bold" style="white-space: pre-wrap;">Recycled</strong></b><span style="white-space: pre-wrap;"> Utility Sand is available by Special Order only and not available for online sale. Minimum quantity of 20 tons apply.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Recycled Utility Sand is recycled concrete sand that is typically used for backfilling trenches, under pavers, concrete slabs, and driveways. Lyngso does not recommend this Recycled Utility Sand for soil mixes and amending, we recommend our Concrete Sand or Olympia Sand instead.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Lyngso Garden Materials sells Recycled Utility Sand in one cubic foot bags. We supply the bags and you fill them! For larger areas, you''ll want to purchase by the ton. We can load your truck, or for a fee, have us deliver to your jobsite. For orders over 20 tons please call us for direct pricing.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Recycled Utility Sand may qualify for LEED Local/Regional Materials and/or Recycled Materials credit. Distances vary for each project location. Please verify the materials accordingly.</span></p>',
    'products',
    281
  );

INSERT INTO
  search_index_content
VALUES
  (
    189,
    'Plaster Sand',
    '<p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">#2 Plaster Sand is used for making mortar or stucco and is a direct substitution for #2 Olympia Sand. Because #2 Plaster Sand is screened and washed it is often used for children''s sand boxes and for volleyball courts.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">We sell the #2 Plaster Sand in one cubic foot bags, we supply the bags and you fill them. For larger areas you''ll want to purchase by the ton. We can load your truck or for a fee, have us deliver to you. For orders over 20 tons please call us for direct pricing.</span></p>',
    'products',
    291
  );

