INSERT INTO
  search_index_content
VALUES
  (
    197,
    'ACID MIX 4-3-6',
    '<p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Down To Earth™ Acid Mix 4-3-6 is a fertilizer blended for plants that thrive in a low pH soil like blueberries and raspberries, rhododendrons, azaleas, hydrangeas, evergreen trees and shrubs. To encourage lush flowers and fruit, apply DTE™ Acid Mix 4-3-6 in early spring for vegetative growth and again when blooms appear. Fall applications promote root growth and boost resistance to extreme winter temperatures.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><b><strong class="editor-text-bold" style="white-space: pre-wrap;">GUARANTEED ANALYSIS</strong></b></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">TOTAL NITROGEN (N) 4.0%</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">0.6% Water Soluble Nitrogen</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">3.4% Water Insoluble Nitrogen</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">AVAILABLE PHOSPHATE (P2O5) 3.0%</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">SOLUBLE POTASH (K2O) 6.0%</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">CALCIUM (Ca) 3.0%</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">MAGNESIUM (Mg) 2.0%</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">SULFUR (S) 2.0%</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Derived from: Cottonseed Meal, Fish Bone Meal, Langbeinite, Rock Phosphate and Kelp Meal</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">ALSO CONTAINS NON-PLANT FOOD INGREDIENT(S):</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">2.5% Humic Acids derived from Leonardite</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><b><strong class="editor-text-bold" style="white-space: pre-wrap;">APPLICATION RATES</strong></b></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">2.5 cups = 1 lb; ½ cup = 3.2 oz; 1 tbsp = 0.4 oz</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Berries:</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">For berry plants 1-2 years old, prepare transplant hole and mix ½ cup with the backfill soil. Use amended soil to fill in around the new plant and water in well. To feed established berries, apply 1 cup per plant in early spring, mix into soil surface and water in well. Repeat application when blooms appear and again in fall at half the recommended amount.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Containers &amp; Houseplants:</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">For new plantings, add 2-4 tbsp. per gallon of soil and mix thoroughly or add 6-10 lbs per cubic yard. For established plants, lightly mix 1-2 tbsp. per gallon into the soil surface once each month during the growing season.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Vegetable Gardens &amp; Flower Beds:</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">To prepare new gardens, apply 3-6 lbs per 100 square feet and thoroughly mix into the top 3" of soil. For new transplants, add 1-2 tbsp. per hole, mix into soil and water in well. To feed established plants, side dress 2-4 oz, depending on plant size and desired growth rate, once each month during the growing season.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Trees &amp; Shrubs:</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Spread 1 lb per 1" of trunk diameter around the base outwards to the drip line, mix into soil surface and water in well. For new trees, prepare transplant hole and mix 1-2 cups with the back-fill soil. Use amended soil to fill in around the new tree and water in well.</span></p>',
    'products',
    401
  );

INSERT INTO
  search_index_content
VALUES
  (
    198,
    'ALFALFA MEAL 2.5-0.5-2.5',
    '<p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Down To Earth™ Alfalfa Meal 2.5-0.5-2.5 is an exceptional source of plant-derived nutrients. It is highly recommended for roses as well as all other vegetables, herbs, flowers and shrubs. DTE™ Alfalfa Meal 2.5-0.5-2.5 is derived from sun-cured, non-genetically modified alfalfa that is freshly milled to preserve the highest plant nutrient value.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: justify;"><b><strong class="editor-text-bold" style="white-space: pre-wrap;">GUARANTEED ANALYSIS</strong></b></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">TOTAL NITROGEN (N) 2.5%</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">2.5% Water Insoluble Nitrogen</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">AVAILABLE PHOSPHATE (P2O5) 0.5%</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">SOLUBLE POTASH (K2O) 2.5%</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Derived from:</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Alfalfa Meal</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Listed by the Organic Materials Review Institute for use in organic production.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><b><strong class="editor-text-bold" style="white-space: pre-wrap;">APPLICATION RATES</strong></b></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">3.5 cups = 1 lb; ½ cup = 2 oz; 1 tbsp = 0.5 oz</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Roses:</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">For </span><b><strong class="editor-text-bold" style="white-space: pre-wrap;">existing</strong></b><span style="white-space: pre-wrap;"> roses, apply 1/2-1 cup per plant in early spring and thoroughly mix into the soil surface. For new roses, add 1/2-1 cup per hole, mix thoroughly into soil and water in well. Repeat application when blooms appear and again in fall at half the recommended amount.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Containers:</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">For new plantings, add 2-4 tbsp. per gallon of soil and mix thoroughly or add 5 lbs. per cubic yard. For established plants, lightly mix 1-2 tbsp. per gallon into the soil surface once each month during the growing season.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Vegetable Gardens &amp; Flower Beds:</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">To prepare smaller gardens, apply 2-4 tbsp. per square foot and thoroughly mix into the top 3" of soil. To prepare larger gardens, apply 5-10 lbs. per 100 square feet and thoroughly mix into the top 3" of soil. For new transplants, add 1-2 tbsp. per hole, mix into soil and water in well. To feed established plants, side dress ½ cup once each month during the growing season to promote plant growth.</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Trees &amp; Shrubs:</span></p><p class="editor-paragraph" dir="ltr" style="text-align: left;"><span style="white-space: pre-wrap;">Spread up to 1 lb per 2" of trunk diameter around the base outwards to the drip line, mix into soil surface and water in well. For new trees, prepare transplant hole and mix 1-2 cups with the back-fill soil. Use the amended soil to fill in around the new tree and water in well. Test</span></p>',
    'products',
    411
  );

