CREATE TABLE
  IF NOT EXISTS "orders" (
    "id" integer primary key autoincrement not null,
    "user_id" integer,
    "guest_name" varchar,
    "guest_email" varchar,
    "shipping_address_id" integer,
    "billing_address_id" integer,
    "checkout_id" integer not null,
    "total" numeric not null,
    "status" varchar not null default ('pending'),
    "created_at" datetime,
    "updated_at" datetime,
    "customer_id" integer,
    foreign key ("checkout_id") references checkouts ("id") on delete cascade on update no action,
    foreign key ("billing_address_id") references addresses ("id") on delete set null on update no action,
    foreign key ("shipping_address_id") references addresses ("id") on delete set null on update no action,
    foreign key ("user_id") references users ("id") on delete set null on update no action,
    foreign key ("customer_id") references "customers" ("id") on delete cascade
  );

