CREATE TABLE
  IF NOT EXISTS "checkouts" (
    "id" integer primary key autoincrement not null,
    "cart_id" integer not null,
    "status" varchar not null default ('pending'),
    "is_pickup" tinyint (1) not null default ('1'),
    "is_delivery" tinyint (1) not null default ('0'),
    "pickup_date" date,
    "pickup_time" varchar,
    "delivery_date" date,
    "delivery_time" varchar,
    "delivery_address_id" integer,
    "billing_address_id" integer,
    "instructions" varchar,
    "created_at" datetime,
    "updated_at" datetime,
    "billing_same_as_shipping" tinyint (1) not null default ('0'),
    "customer_id" integer,
    foreign key ("billing_address_id") references addresses ("id") on delete set null on update no action,
    foreign key ("delivery_address_id") references addresses ("id") on delete set null on update no action,
    foreign key ("cart_id") references carts ("id") on delete cascade on update no action,
    foreign key ("customer_id") references "customers" ("id") on delete cascade
  );

