CREATE TABLE
  IF NOT EXISTS "addresses" (
    "id" integer primary key autoincrement not null,
    "name" varchar,
    "street1" varchar not null,
    "street2" varchar,
    "city" varchar not null,
    "state" varchar not null,
    "zip" varchar not null,
    "country" varchar not null default ('USA'),
    "phone" varchar not null,
    "default" tinyint (1) not null default ('0'),
    "billing" tinyint (1) not null default ('1'),
    "created_at" datetime,
    "updated_at" datetime,
    "customer_id" integer,
    foreign key ("customer_id") references customers ("id") on delete cascade on update no action
  );

